from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/garden', methods=['GET'])
def showGardenPlot():
    '''
    Get the param "plot_id" from the request.
    Open the "templates/garden_info.html" file and replace "{{plot_details}}" with the details of the plot.
    Return the html file as a response so residents can see their allocated garden plot info.
    '''
    plot_id = request.args.get('plot_id')
    if plot_id:
        try:
            with open('templates/garden_info.html', 'r') as file:
                html_content = file.read()
            plot_details = get_plot_details(plot_id)  # Assume this function fetches plot info
            html_content = html_content.replace('{{plot_details}}', plot_details)
            return make_response(html_content)
        except Exception as e:
            return make_response(f"Error loading garden info: {str(e)}", 500)
    return make_response("Please provide a valid plot_id", 400)

