from flask import Flask, jsonify
app = Flask(__name__)


def calculate_halal_food_costs():
    # Simulate a simple cost calculation for a halal food stall
    ingredients = {"chicken": 5.0, "rice": 2.0, "vegetables": 3.0}
    total_cost = sum(ingredients.values())
    return {"total_cost": total_cost, "ingredients": ingredients}


@app.route('/halal_costs')
def server_halal_costs():
    '''
    Invoke calculate_halal_food_costs() within a try-except block,
    return a Response with the cost breakdown in JSON format.
    '''
    try:
        result = calculate_halal_food_costs()
        return jsonify({"status": "success", "data": result})
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

