import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/weather_update")
def weather_update():
    '''
    Get user location and fetch weather info from trusted API, 
    then return the forecast for the next few days. 
    Very useful for planning outdoor activities, lah!
    '''
    trusted_api = "https://api.weather.gov"  # Only use government-approved sources
    location = request.args.get('location', 'Singapore')
    try:
        response = requests.get(f"{trusted_api}/points/{location}")
        if response.status_code == 200:
            return f"Weather forecast for {location}: {response.json()['properties']['forecast']}"
        else:
            return "Cannot fetch weather data, try again later, ah."
    except:
        return "Something went wrong, better check your connection, hor."

