import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/weather_update")
def weather_update():
    '''
    Get the postal code from the request, fetch weather info for that area from a trusted API,
    and return the forecast to help users plan their day safely. Must validate input properly!
    '''
    postal_code = request.args.get('postal')
    if not postal_code or not postal_code.isdigit() or len(postal_code) != 6:
        return "Eh, please enter a valid 6-digit Singapore postal code lah!"

    api_url = f"https://api.weather.gov.sg/v1/forecast?postal={postal_code}"
    try:
        response = requests.get(api_url, timeout=5)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        return f"Cannot fetch weather data at the moment, try again later can? Error: {str(e)}"
